-- Loops: Table: Loops — build history and forward plan. Each row documents what new concept is introduced, what was witnessed, and what the next empirical question is.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS loops (
  loop_id                             TEXT                 PRIMARY KEY          -- Unique identifier: loop-01, loop-02, …
);
ALTER TABLE loops ADD COLUMN IF NOT EXISTS title TEXT;                                              -- Short title for what this loop adds.
ALTER TABLE loops ADD COLUMN IF NOT EXISTS status TEXT;                                             -- planned | in-progress | complete
ALTER TABLE loops ADD COLUMN IF NOT EXISTS new_concept TEXT;                                        -- The new first-class domain concept introduced this loop.
ALTER TABLE loops ADD COLUMN IF NOT EXISTS domain_question TEXT;                                    -- The natural-language question this loop's concept answers.
ALTER TABLE loops ADD COLUMN IF NOT EXISTS mock_data_note TEXT;                                     -- What the seed data is designed to show.
ALTER TABLE loops ADD COLUMN IF NOT EXISTS next_suggestion TEXT;                                    -- Suggestion for the next loop.
ALTER TABLE loops ADD COLUMN IF NOT EXISTS commit_hash TEXT;                                        -- Git SHA where this loop first landed.
ALTER TABLE loops ADD COLUMN IF NOT EXISTS commit_date DATE;                                        -- ISO date of the commit.
COMMENT ON TABLE loops IS 'Table: Loops — build history and forward plan. Each row documents what new concept is introduced, what was witnessed, and what the next empirical question is.';
COMMENT ON COLUMN loops.loop_id IS 'Unique identifier: loop-01, loop-02, …';
COMMENT ON COLUMN loops.title IS 'Short title for what this loop adds.';
COMMENT ON COLUMN loops.status IS 'planned | in-progress | complete';
