-- ----------------------------------------------------------------------------
-- Charges: Table: Charges — individual charged particles with 3D position and physical properties. The raw leaves of the Coulomb's Law DAG.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS charges (
