);
ALTER TABLE charges ADD COLUMN IF NOT EXISTS name TEXT;                                             -- Human-readable label (Proton A, Electron B, …)
ALTER TABLE charges ADD COLUMN IF NOT EXISTS system_id TEXT;                                        -- FK → Systems.SystemId — which physical system this charge belongs to
ALTER TABLE charges ADD COLUMN IF NOT EXISTS particle_id TEXT;                                      -- FK → Particles.ParticleId — archetype (optional)
ALTER TABLE charges ADD COLUMN IF NOT EXISTS charge_value NUMERIC;                                  -- Charge in Coulombs (signed: positive or negative)
ALTER TABLE charges ADD COLUMN IF NOT EXISTS position_x NUMERIC;                                    -- X coordinate in meters
ALTER TABLE charges ADD COLUMN IF NOT EXISTS position_y NUMERIC;                                    -- Y coordinate in meters
ALTER TABLE charges ADD COLUMN IF NOT EXISTS position_z NUMERIC;                                    -- Z coordinate in meters
ALTER TABLE charges ADD COLUMN IF NOT EXISTS mass NUMERIC;                                          -- Mass in kg (null = massless / not tracked)
COMMENT ON TABLE charges IS 'Table: Charges — individual charged particles with 3D position and physical properties. The raw leaves of the Coulomb''s Law DAG.';
COMMENT ON COLUMN charges.charge_id IS 'Unique identifier';
COMMENT ON COLUMN charges.name IS 'Human-readable label (Proton A, Electron B, …)';
