COMMENT ON COLUMN charges.particle_id IS 'FK → Particles.ParticleId — archetype (optional)';
COMMENT ON COLUMN charges.charge_value IS 'Charge in Coulombs (signed: positive or negative)';
COMMENT ON COLUMN charges.position_x IS 'X coordinate in meters';
COMMENT ON COLUMN charges.position_y IS 'Y coordinate in meters';
COMMENT ON COLUMN charges.position_z IS 'Z coordinate in meters';
COMMENT ON COLUMN charges.mass IS 'Mass in kg (null = massless / not tracked)';

