-- ----------------------------------------------------------------------------
-- ChargeInteractions: Table: ChargeInteractions — pairwise electrostatic interactions. One row per ordered pair (Charge1, Charge2) within a system. Position and charge values are stored directly (denormalized from Charges) so that DeltaX/Y/Z, DistanceMeters, ForceMagnitude, IsAttractive, and IsRepulsive can be computed as calculated fields. F = k·|q₁·q₂|/r² falls out of the DAG.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS charge_interactions (
  interaction_id                      TEXT                 PRIMARY KEY          -- Unique identifier
);
ALTER TABLE charge_interactions ADD COLUMN IF NOT EXISTS system_id TEXT;                            -- FK → Systems.SystemId
ALTER TABLE charge_interactions ADD COLUMN IF NOT EXISTS charge1_id TEXT;                           -- FK → Charges.ChargeId (first particle)
ALTER TABLE charge_interactions ADD COLUMN IF NOT EXISTS charge2_id TEXT;                           -- FK → Charges.ChargeId (second particle)
ALTER TABLE charge_interactions ADD COLUMN IF NOT EXISTS charge1_label TEXT;                        -- Human label copied from Charges.Name at seed time
ALTER TABLE charge_interactions ADD COLUMN IF NOT EXISTS charge2_label TEXT;                        -- Human label copied from Charges.Name at seed time
ALTER TABLE charge_interactions ADD COLUMN IF NOT EXISTS q1 NUMERIC;                                -- Charge value of Charge1 in Coulombs (copied from Charges.ChargeValue)
ALTER TABLE charge_interactions ADD COLUMN IF NOT EXISTS q2 NUMERIC;                                -- Charge value of Charge2 in Coulombs (copied from Charges.ChargeValue)
ALTER TABLE charge_interactions ADD COLUMN IF NOT EXISTS x1 NUMERIC;                                -- X position of Charge1 in meters (copied from Charges.PositionX)
ALTER TABLE charge_interactions ADD COLUMN IF NOT EXISTS y1 NUMERIC;                                -- Y position of Charge1 in meters (copied from Charges.PositionY)
ALTER TABLE charge_interactions ADD COLUMN IF NOT EXISTS z1 NUMERIC;                                -- Z position of Charge1 in meters (copied from Charges.PositionZ)
ALTER TABLE charge_interactions ADD COLUMN IF NOT EXISTS x2 NUMERIC;                                -- X position of Charge2 in meters (copied from Charges.PositionX)
ALTER TABLE charge_interactions ADD COLUMN IF NOT EXISTS y2 NUMERIC;                                -- Y position of Charge2 in meters (copied from Charges.PositionY)
ALTER TABLE charge_interactions ADD COLUMN IF NOT EXISTS z2 NUMERIC;                                -- Z position of Charge2 in meters (copied from Charges.PositionZ)
ALTER TABLE charge_interactions ADD COLUMN IF NOT EXISTS coulomb_k NUMERIC;                         -- Coulomb's constant: 8.99×10⁹ N·m²·C⁻². Stored per-row so the formula is self-contained.
COMMENT ON TABLE charge_interactions IS 'Table: ChargeInteractions — pairwise electrostatic interactions. One row per ordered pair (Charge1, Charge2) within a system. Position and charge values are stored directly (denormalized from Charges) so that DeltaX/Y/Z, DistanceMeters, ForceMagnitude, IsAttractive, and IsRepulsive can be computed as calculated fields. F = k·|q₁·q₂|/r² falls out of the DAG.';
COMMENT ON COLUMN charge_interactions.interaction_id IS 'Unique identifier';
COMMENT ON COLUMN charge_interactions.system_id IS 'FK → Systems.SystemId';
COMMENT ON COLUMN charge_interactions.charge1_id IS 'FK → Charges.ChargeId (first particle)';
COMMENT ON COLUMN charge_interactions.charge2_id IS 'FK → Charges.ChargeId (second particle)';
COMMENT ON COLUMN charge_interactions.charge1_label IS 'Human label copied from Charges.Name at seed time';
COMMENT ON COLUMN charge_interactions.charge2_label IS 'Human label copied from Charges.Name at seed time';
COMMENT ON COLUMN charge_interactions.q1 IS 'Charge value of Charge1 in Coulombs (copied from Charges.ChargeValue)';
COMMENT ON COLUMN charge_interactions.q2 IS 'Charge value of Charge2 in Coulombs (copied from Charges.ChargeValue)';
COMMENT ON COLUMN charge_interactions.x1 IS 'X position of Charge1 in meters (copied from Charges.PositionX)';
COMMENT ON COLUMN charge_interactions.y1 IS 'Y position of Charge1 in meters (copied from Charges.PositionY)';
COMMENT ON COLUMN charge_interactions.z1 IS 'Z position of Charge1 in meters (copied from Charges.PositionZ)';
