-- ----------------------------------------------------------------------------
-- ForceVectors: Table: ForceVectors — unit vector and full Cartesian force components for each ChargeInteraction. FX, FY, FZ decompose the scalar ForceMagnitude along the displacement direction. Force on Charge1 due to Charge2: attractive → pulls C1 toward C2 (−r̂); repulsive → pushes C1 away from C2 (+r̂). Position and interaction values are stored directly (denormalized) so all components compute as pure calculated fields.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS force_vectors (
  force_vector_id                     TEXT                 PRIMARY KEY          -- Unique identifier (mirrors InteractionId)
);
ALTER TABLE force_vectors ADD COLUMN IF NOT EXISTS interaction_id TEXT;                             -- FK → ChargeInteractions.InteractionId
ALTER TABLE force_vectors ADD COLUMN IF NOT EXISTS force_magnitude_raw NUMERIC;                     -- Scalar force magnitude in Newtons (copied from ChargeInteractions.ForceMagnitude)
ALTER TABLE force_vectors ADD COLUMN IF NOT EXISTS dx NUMERIC;                                      -- ΔX = X2 − X1 in meters (copied from ChargeInteractions.DeltaX)
ALTER TABLE force_vectors ADD COLUMN IF NOT EXISTS dy NUMERIC;                                      -- ΔY = Y2 − Y1 in meters (copied from ChargeInteractions.DeltaY)
ALTER TABLE force_vectors ADD COLUMN IF NOT EXISTS dz NUMERIC;                                      -- ΔZ = Z2 − Z1 in meters (copied from ChargeInteractions.DeltaZ)
ALTER TABLE force_vectors ADD COLUMN IF NOT EXISTS dist_raw NUMERIC;                                -- Separation distance r in meters (copied from ChargeInteractions.DistanceMeters)
ALTER TABLE force_vectors ADD COLUMN IF NOT EXISTS is_attractive_raw BOOLEAN;                       -- Attraction flag (copied from ChargeInteractions.IsAttractive)
COMMENT ON TABLE force_vectors IS 'Table: ForceVectors — unit vector and full Cartesian force components for each ChargeInteraction. FX, FY, FZ decompose the scalar ForceMagnitude along the displacement direction. Force on Charge1 due to Charge2: attractive → pulls C1 toward C2 (−r̂); repulsive → pushes C1 away from C2 (+r̂). Position and interaction values are stored directly (denormalized) so all components compute as pure calculated fields.';
COMMENT ON COLUMN force_vectors.force_vector_id IS 'Unique identifier (mirrors InteractionId)';
COMMENT ON COLUMN force_vectors.interaction_id IS 'FK → ChargeInteractions.InteractionId';
COMMENT ON COLUMN force_vectors.force_magnitude_raw IS 'Scalar force magnitude in Newtons (copied from ChargeInteractions.ForceMagnitude)';
COMMENT ON COLUMN force_vectors.dx IS 'ΔX = X2 − X1 in meters (copied from ChargeInteractions.DeltaX)';
COMMENT ON COLUMN force_vectors.dy IS 'ΔY = Y2 − Y1 in meters (copied from ChargeInteractions.DeltaY)';
COMMENT ON COLUMN force_vectors.dz IS 'ΔZ = Z2 − Z1 in meters (copied from ChargeInteractions.DeltaZ)';
COMMENT ON COLUMN force_vectors.dist_raw IS 'Separation distance r in meters (copied from ChargeInteractions.DistanceMeters)';
COMMENT ON COLUMN force_vectors.is_attractive_raw IS 'Attraction flag (copied from ChargeInteractions.IsAttractive)';

